import React from 'react';
import { GoogleLogin } from '@react-oauth/google';
import { useNavigate } from 'react-router-dom';

function Home() {
  const navigate = useNavigate();

  return (
    <div>
      {/* Título com cor azul clara para destacar no fundo escuro */}
      <h1 style={{ color: '#38bdf8', fontSize: '2rem', marginBottom: '20px' }}>
        Entrada do Sistema
      </h1>
      
      {/* Container do botão do Google com espaçamento */}
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        marginBottom: '30px',
        minHeight: '40px' 
      }}>
        <GoogleLogin 
          onSuccess={res => {
            console.log('Login realizado com sucesso:', res);
            // Aqui você poderia navegar para o cadastro após o login
            // navigate('/cadastro');
          }}
          onError={() => console.log('Falha na autenticação')}
          theme="filled_blue"
          shape="pill"
          size="large"
          locale="pt_BR"
        />
      </div>

      {/* Botão de navegação estilizado */}
      <button 
        onClick={() => navigate('/dupla')}
        style={{
          width: '100%',
          padding: '14px',
          borderRadius: '10px',
          border: '1px solid #475569',
          backgroundColor: '#334155',
          color: '#f8fafc',
          fontSize: '16px',
          fontWeight: '600',
          cursor: 'pointer',
          transition: 'all 0.3s ease'
        }}
        // Efeito simples de hover via JS (opcional, já que o CSS global deve cobrir)
        onMouseOver={(e) => e.target.style.backgroundColor = '#38bdf8'}
        onMouseOut={(e) => e.target.style.backgroundColor = '#334155'}
      >
        Ver Informações do Aluno
      </button>

      <p style={{ marginTop: '20px', fontSize: '0.8rem', color: '#94a3b8' }}>
        Matrícula: 20241000941
      </p>
    </div>
  );
}

export default Home;
